/// Sensitivity level for data classification
enum DataSensitivity {
    case publicData
    case internalOnly
    case sensitive
    case restricted // PII, tokens, passwords - NEVER log
}

/// Log level
enum LogLevel: Int, Comparable {
    case verbose = 0
    case debug = 1
    case info = 2
    case warning = 3
    case error = 4
    case critical = 5
    
    static func < (lhs: LogLevel, rhs: LogLevel) -> Bool {
        lhs.rawValue < rhs.rawValue
    }
    
    var emoji: String {
        switch self {
        case .verbose: return "📝"
        case .debug: return "🔍"
        case .info: return "ℹ️"
        case .warning: return "⚠️"
        case .error: return "❌"
        case .critical: return "🚨"
        }
    }
    
    var osLogType: OSLogType {
        switch self {
        case .verbose, .debug: return .debug
        case .info: return .info
        case .warning: return .default
        case .error: return .error
        case .critical: return .fault
        }
    }
}

// MARK: - Data Redaction Utilities

struct DataRedactor {
    
    /// Redacts an email address: "user@example.com" -> "u***@e***.com"
    static func redactEmail(_ email: String) -> String {
        let components = email.split(separator: "@")
        guard components.count == 2 else { return "[invalid-email]" }
        let localPart = String(components[0])
        let domainPart = String(components[1])
        let redactedLocal = String(localPart.prefix(1)) + "***"
        let domainComponents = domainPart.split(separator: ".")
        guard let firstDomain = domainComponents.first, let tld = domainComponents.last else {
            return redactedLocal + "@[redacted]"
        }
        let redactedDomain = String(firstDomain.prefix(1)) + "***." + tld
        return redactedLocal + "@" + redactedDomain
    }
    
    /// Redacts a user ID, showing only last 4 characters
    static func redactUserID(_ userID: String) -> String {
        guard userID.count > 4 else { return "[redacted-id]" }
        return "***" + String(userID.suffix(4))
    }
    
    /// Completely redacts sensitive values (tokens, passwords, etc.)
    static func redactSensitive(_ value: String) -> String {
        guard !value.isEmpty else { return "[empty]" }
        return "[REDACTED-\(value.count)chars]"
    }
    
    /// Redacts known sensitive keys from a dictionary
    static func redactDictionary(_ dict: [String: Any]) -> [String: Any] {
        let sensitiveKeys: Set<String> = [
            "password", "token", "access_token", "refresh_token",
            "authorization", "secret", "api_key", "apikey",
            "credit_card", "card_number", "cvv", "ssn",
            "social_security", "pin", "otp", "mfa_code",
            "private_key", "session_id", "cookie", "bearer"
        ]
        
        let piiKeys: Set<String> = [
            "email", "phone", "address", "date_of_birth",
            "first_name", "last_name", "full_name", "name"
        ]
        
        var redacted = [String: Any]()
        for (key, value) in dict {
            let lowercasedKey = key.lowercased()
            if sensitiveKeys.contains(lowercasedKey) {
                redacted[key] = "[REDACTED]"
            } else if piiKeys.contains(lowercasedKey) {
                if let stringValue = value as? String {
                    if lowercasedKey == "email" {
                        redacted[key] = redactEmail(stringValue)
                    } else {
                        redacted[key] = String(stringValue.prefix(1)) + "***"
                    }
                } else {
                    redacted[key] = "[REDACTED-PII]"
                }
            } else if let nestedDict = value as? [String: Any] {
                redacted[key] = redactDictionary(nestedDict)
            } else {
                redacted[key] = value
            }
        }
        return redacted
    }
    
    /// Redacts HTTP headers, removing auth tokens
    static func redactHeaders(_ headers: [String: String]) -> [String: String] {
        let sensitiveHeaders: Set<String> = [
            "authorization", "cookie", "set-cookie",
            "x-api-key", "x-auth-token", "proxy-authorization"
        ]
        var redacted = headers
        for (key, _) in headers {
            if sensitiveHeaders.contains(key.lowercased()) {
                redacted[key] = "[REDACTED]"
            }
        }
        return redacted
    }
}

