// MARK: - Secure Log Storage

final class SecureLogStorage {
    
    private let queue = DispatchQueue(label: "com.app.securelogstorage", qos: .utility)
    private var entries: [LogEntry] = []
    private let maxEntries: Int
    private let fileManager = FileManager.default
    
    init(maxEntries: Int = 1000) {
        self.maxEntries = maxEntries
    }
    
    func append(_ entry: LogEntry) {
        queue.async { [weak self] in
            guard let self = self else { return }
            self.entries.append(entry)
            if self.entries.count > self.maxEntries {
                self.entries.removeFirst(self.entries.count - self.maxEntries)
            }
        }
    }
    
    func getEntries(completion: @escaping ([LogEntry]) -> Void) {
        queue.async { [weak self] in
            completion(self?.entries ?? [])
        }
    }
    
    func exportForSupport(completion: @escaping (Data?) -> Void) {
        queue.async { [weak self] in
            guard let entries = self?.entries else {
                completion(nil)
                return
            }
            let encoder = JSONEncoder()
            encoder.dateEncodingStrategy = .iso8601
            encoder.outputFormatting = .prettyPrinted
            let data = try? encoder.encode(entries)
            completion(data)
        }
    }
    
    func clear() {
        queue.async { [weak self] in
            self?.entries.removeAll()
        }
    }
}

