// MARK: - Secure Logger

final class SecureLogger {
    
    static let shared = SecureLogger()
    
    private let osLog: OSLog
    private let storage: SecureLogStorage
    private let configuration: BuildConfiguration
    private let queue = DispatchQueue(label: "com.app.securelogger", qos: .utility)
    
    private init() {
        self.osLog = OSLog(subsystem: Bundle.main.bundleIdentifier ?? "com.app", category: "AppLog")
        self.storage = SecureLogStorage(maxEntries: 2000)
        self.configuration = BuildConfiguration.current
    }
    
    // MARK: - Core Logging
    
    func log(
        _ level: LogLevel,
        category: String,
        message: String,
        metadata: [String: String]? = nil,
        file: String = #file,
        function: String = #function,
        line: Int = #line
    ) {
        guard level >= configuration.minimumLogLevel else { return }
        
        let fileName = (file as NSString).lastPathComponent
        
        let entry = LogEntry(
            id: UUID(),
            timestamp: Date(),
            level: "\(level)",
            category: category,
            message: message,
            metadata: metadata,
            file: fileName,
            function: function,
            line: line
        )
        
        storage.append(entry)
        
        // Use os_log for structured logging (respects privacy by default)
        // In release builds, os_log redacts dynamic strings automatically
        let formattedMessage = "\(level.emoji) [\(category)] \(message) (\(fileName):\(line))"
        os_log("%{public}s", log: osLog, type: level.osLogType, formattedMessage)
        
        // Console output ONLY in debug builds
        #if DEBUG
        if configuration.allowsConsoleOutput {
            debugPrint("[\(ISO8601DateFormatter().string(from: entry.timestamp))] \(formattedMessage)")
        }
        #endif
    }
    
    // MARK: - Convenience Methods
    
    func verbose(_ message: String, category: String = "General", metadata: [String: String]? = nil,
                 file: String = #file, function: String = #function, line: Int = #line) {
        log(.verbose, category: category, message: message, metadata: metadata, file: file, function: function, line: line)
    }
    
    func debug(_ message: String, category: String = "General", metadata: [String: String]? = nil,
               file: String = #file, function: String = #function, line: Int = #line) {
        log(.debug, category: category, message: message, metadata: metadata, file: file, function: function, line: line)
    }
    
    func info(_ message: String, category: String = "General", metadata: [String: String]? = nil,
              file: String = #file, function: String = #function, line: Int = #line) {
        log(.info, category: category, message: message, metadata: metadata, file: file, function: function, line: line)
    }
    
    func warning(_ message: String, category: String = "General", metadata: [String: String]? = nil,
                 file: String = #file, function: String = #function, line: Int = #line) {
        log(.warning, category: category, message: message, metadata: metadata, file: file, function: function, line: line)
    }
    
    func error(_ message: String, category: String = "General", metadata: [String: String]? = nil,
               file: String = #file, function: String = #function, line: Int = #line) {
        log(.error, category: category, message: message, metadata: metadata, file: file, function: function, line: line)
    }
    
    func critical(_ message: String, category: String = "General", metadata: [String: String]? = nil,
                  file: String = #file, function: String = #function, line: Int = #line) {
        log(.critical, category: category, message: message, metadata: metadata, file: file, function: function, line: line)
