// MARK: - Auth Flow Tracker (Secure)

final class AuthFlowTracker {
    
    private let logger = SecureLogger.shared
    private let category = "Auth"
    
    func trackLoginAttempt(email: String, method: String) {
        // NEVER log the actual email or password
        logger.info(
            "Login attempt via \(method)",
            category: category,
            metadata: [
                "email_hint": DataRedactor.redactEmail(email),
                "method": method
            ]
        )
    }
    
    func trackLoginSuccess(userID: String) {
        // Only log redacted user ID
        logger.info(
            "Login successful",
            category: category,
            metadata: [
                "user_hint": DataRedactor.redactUserID(userID)
            ]
        )
    }
    
    func trackLoginFailure(email: String, errorCode: Int, errorMessage: String) {
        logger.warning(
            "Login failed with code \(errorCode)",
            category: category,
            metadata: [
                "email_hint": DataRedactor.redactEmail(email),
                "error_code": "\(errorCode)",
                "error_type": sanitizeErrorMessage(errorMessage)
            ]
        )
    }
    
    func trackTokenRefresh(success: Bool) {
        // NEVER log the actual token
        logger.info(
            "Token refresh \(success ? "succeeded" : "failed")",
            category: category,
            metadata: ["success": "\(success)"]
        )
    }
    
    func trackLogout(userID: String, reason: String) {
        logger.info(
            "User logged out: \(reason)",
            category: category,
            metadata: [
                "user_hint": DataRedactor.redactUserID(userID),
                "reason": reason
            ]
        )
    }
    
    func trackMFAChallenge(type: String) {
        // NEVER log MFA codes
        logger.info(
            "MFA challenge presented",
            category: category,
            metadata: ["mfa_type": type]
        )
    }
    
    func trackMFAResult(success: Bool) {
        logger.info(
            "MFA verification \(success ? "succeeded" : "failed")",
            category: category,
            metadata: ["success": "\(success)"]
        )
    }
    
    /// Strips potentially sensitive info from error messages
    private func sanitizeErrorMessage(_ message: String) -> String {
        // Remove anything that looks like tokens, emails, or IDs from error messages
        var sanitized = message
        
        // Remove email patterns
        let emailPattern = "[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\\.[A-Za-z]{2,}"
        if let regex = try? NSRegularExpression(pattern: emailPattern) {
            sanitized = regex.stringByReplacingMatches(
                in: sanitized,
                range: NSRange(sanitized.startIndex..., in: sanitized),
                withTemplate: "[REDACTED-EMAIL]"
            )
        }
        
        // Remove long hex/base64 strings that might be tokens
        let tokenPattern = "[A-Za-z0-9+/=_-]{32,}"
        if let regex = try? NSRegularExpression(pattern: tokenPattern) {
            sanitized = regex.stringByReplacingMatches(
                in: sanitized,
                range: NSRange(sanitized.startIndex..., in: sanitized),
                withTemplate: "[REDACTED-TOKEN]"
            )
        }
        
        return sanitized
    }
}

// MARK: - API Call Tracker (Secure)

final class APICallTracker {
    
    private let logger = SecureLogger.shared
    private let category = "API"
    
    func trackRequest(
        method: String,
        endpoint: String,
        headers: [String: String]?,
        bodySize: Int?
    ) {
        // Log the endpoint and method, but NEVER log auth headers or request bodies
        let safeEndpoint = redactQueryParameters(endpoint)
        
        logger.info(
            "\(method) \(safeEndpoint)",
            category: category,
            metadata: [
                "method": method,
                "endpoint": safeEndpoint,
                "headers_present": headers != nil ? "true" : "false",
                "body_size": bodySize.map { "\($0) bytes" } ?? "none"
            ]
        )
    }
    
    func trackResponse(
        method: String,
        endpoint: String,
        statusCode: Int,
        duration: TimeInterval,
        responseSize: Int?
    ) {
        let safeEndpoint = redactQueryParameters(endpoint)
        let level: LogLevel = statusCode >= 400 ? .warning : .info
        
        logger.log(
            level,
            category: category,
            message: "\(method) \(safeEndpoint) -> \(statusCode) (\(String(format: "%.2f", duration))s)",
            metadata: [
                "method": method,
                "endpoint": safeEndpoint,
                "status_code": "\(statusCode)",
                "duration_ms": "\(Int(duration * 1000))",
                "response_size": responseSize.map { "\($0) bytes" } ?? "unknown"
            ]
        )
    }
    
    func trackAPIError(
        method: String,
        endpoint: String,
        error: Error,
        statusCode: Int?
    ) {
        let safeEndpoint = redactQueryParameters(endpoint)
        
        logger.error(
            "API Error: \(method) \(safeEndpoint) - \(type(of: error))",
            category: category,
            metadata: [
                "method": method,
                "endpoint": safeEndpoint,
                "error_type": "\(type(of: error))",
                "error_domain": (error as NSError).domain,
                "error_code": "\((error as NSError).code)",
                "status_code": statusCode.map { "\($0)" } ?? "none"
            ]
        )
    }
    
    func trackTimeout(method: String, endpoint: String, duration: TimeInterval) {
        let safeEndpoint = redactQueryParameters(endpoint)
        
        logger.warning(
            "Request timeout: \(method) \(safeEndpoint) after \(String(format: "%.1f", duration))s",
            category: category,
            metadata: [
                "method": method,
                "endpoint": safeEndpoint,
                "duration_ms": "\(Int(duration * 1000))"
            ]
        )
    }
    
    /// Redacts sensitive query parameters from URLs
    private func redactQueryParameters(_ endpoint: String) -> String {
        guard let urlComponents = URLComponents(string: endpoint) else { return endpoint }
        
        let sensitiveParams: Set<String> = [
            "token", "access_token", "api_key", "key", "secret",
            "password", "email", "phone", "session"
        ]
        
        guard var queryItems = urlComponents.queryItems, !queryItems.isEmpty else {
            return urlComponents.path
        }
        
        for i in 0..<queryItems.count {
            if sensitiveParams.contains(queryItems[i].name.lowercased()) {
                queryItems[i] = URLQueryItem(name: queryItems[i].name, value: "[REDACTED]")
            }
        }
        
        var safe = urlComponents
        safe.queryItems = queryItems
        return safe.path + (safe.query.map { "?\($0)" } ?? "")
    }
}

