// MARK: - Error Tracker (Secure)

final class ErrorTracker {
    
    private let logger = SecureLogger.shared
    private let category = "Error"
    
    func trackError(
        _ error: Error,
        context: String,
        userID: String? = nil,
        additionalInfo: [String: String]? = nil
    ) {
        var metadata: [String: String] = [
            "error_type": "\(type(of: error))",
            "error_domain": (error as NSError).domain,
            "error_code": "\((error as NSError).code)",
            "context": context
        ]
        
        if let userID = userID {
            metadata["user_hint"] = DataRedactor.redactUserID(userID)
        }
        
        // Filter additional info for sensitive data
        if let additionalInfo = additionalInfo {
            for (key, value) in additionalInfo {
                let sensitiveKeys: Set<String> = ["token", "password", "email", "phone", "ssn"]
                if sensitiveKeys.contains(key.lowercased()) {
                    metadata["extra_\(key)"] = "[REDACTED]"
                } else {
                    metadata["extra_\(key)"] = value
                }
            }
        }
        
        logger.error(
            "Error in \(context): \(type(of: error)) code=\((error as NSError).code)",
            category: category,
            metadata: metadata
        )
    }
    
    func trackCrashPrecondition(
        reason: String,
        file: String = #file,
        function: String = #function,
        line: Int = #line
    ) {
        logger.critical(
            "Crash precondition: \(reason)",
            category: category,
            metadata: [
                "reason": reason,
                "file": (file as NSString).lastPathComponent,
                "function": function,
                "line": "\(line)"
            ]
        )
    }
    
    func trackUnexpectedState(
        description: String,
        expected: String,
        actual: String
    ) {
        logger.warning(
            "Unexpected state: \(description)",
            category: category,
            metadata: [
                "description": description,
                "expected": expected,
                "actual": actual
            ]
        )
    }
}

