// MARK: - Performance Tracker

final class PerformanceTracker {
    
    private let logger = SecureLogger.shared
    private let category = "Performance"
    private var timers: [String: CFAbsoluteTime] = [:]
    private let queue = DispatchQueue(label: "com.app.performancetracker")
    
    func startTimer(_ name: String) {
        queue.sync {
            timers[name] = CFAbsoluteTimeGetCurrent()
        }
    }
    
    func endTimer(_ name: String) {
        queue.sync {
            guard let startTime = timers[name] else {
                logger.warning("Timer '\(name)' was never started", category: category)
                return
            }
            let duration = CFAbsoluteTimeGetCurrent() - startTime
            timers.removeValue(forKey: name)
            
            let level: LogLevel = duration > 3.0 ? .warning : .info
            logger.log(
                level,
                category: category,
                message: "Timer '\(name)': \(String(format: "%.2f", duration))s",
                metadata: [
                    "timer_name": name,
                    "duration_ms": "\(Int(duration * 1000))"
                ]
            )
        }
    }
    
    func trackMemoryWarning() {
        logger.warning(
            "Memory warning received",
            category: category,
            metadata: [
                "memory_used": "\(getMemoryUsage()) MB"
            ]
        )
    }
    
    private func getMemoryUsage() -> String {
        var info = mach_task_basic_info()
        var count = mach_msg_type_number_t(MemoryLayout<mach_task_basic_info>.size) / 4
        let result = withUnsafeMutablePointer(to: &info) {
            $0.withMemoryRebound(to: integer_t.self, capacity: Int(count)) {
                task_info(mach_task_self_, task_flavor_t(MACH_TASK_BASIC_INFO), $0, &count)
            }
        }
        if result == KERN_SUCCESS {
            return String(format: "%.1f", Double(info.resident_size) / 1_048_576.0)
        }
        return "unknown"
    }
}

